# ============================================================
# FUNKSIONI I INSERT
# ============================================================
def generate_products():
    logger.info("=" * 60)
    logger.info("DUKE FILLUAR GJENERIMIN E 500 PRODUKTEVE")
    logger.info("=" * 60)

    success_count = 0
    error_count   = 0
    errors        = []

    for i, product in enumerate(products, 1):
        try:
            data = {
                "product_id":      product[0],
                "product_name":    product[1],
                "category_id":     product[2],
                "supplier_id":     product[3],
                "unit_price":      product[4],
                "unit_cost":       product[5],
                "weight_kg":       product[6],
                "shelf_life_days": product[7],
                "min_stock":       product[8],
                "max_stock":       product[9],
                "reorder_point":   product[10],
                "reorder_qty":     product[11],
                "abc_class":       product[12],
                "xyz_class":       product[13],
            }

            response = supabase.table("products").upsert(data).execute()

            if response.data:
                success_count += 1
                if i % 50 == 0:
                    logger.info(f"✅ Progres: {i}/500 produkte të insertuara")
            else:
                error_count += 1
                errors.append(f"PRD {product[0]}: Nuk u kthye data")
                logger.warning(f"⚠️  {product[0]} - {product[1]}: nuk u insertua")

        except Exception as e:
            error_count += 1
            errors.append(f"{product[0]}: {str(e)}")
            logger.error(f"❌ ERROR te {product[0]} - {product[1]}: {e}")

    # ============================================================
    # RAPORT FINAL
    # ============================================================
    logger.info("=" * 60)
    logger.info("RAPORT FINAL:")
    logger.info(f"  ✅ Të insertuara me sukses : {success_count}/500")
    logger.info(f"  ❌ Gabime                  : {error_count}")
    if errors:
        logger.info("  LISTA E GABIMEVE:")
        for err in errors:
            logger.error(f"    → {err}")
    logger.info("=" * 60)

    return success_count, error_count


# ============================================================
# MAIN
# ============================================================
if __name__ == "__main__":
    try:
        success, errors = generate_products()
        if errors == 0:
            logger.info("🎉 TË GJITHA 500 PRODUKTET U GJENERUAN ME SUKSES!")
        else:
            logger.warning(f"⚠️  Perfundoi me {errors} gabime. Kontrollo log-un.")
    except Exception as e:
        logger.critical(f"❌ KRITIKE: Skripti dështoi plotësisht: {e}")
        sys.exit(1)